	.hero-bottom { align-items: center; color: var(--color-muted); display: flex; font-size: .72rem; font-weight: 600; gap: .55rem; letter-spacing: .07em; margin-top: clamp(3.5rem, 9vh, 7rem); text-transform: uppercase; } .pulse { width: .52rem; height: .52rem; border-radius: 100%; background: var(--color-aqua); box-shadow: 0 0 0 .3rem rgba(82,225,207,.1); } .line { width: 3rem; height: 1px; background: var(--color-line); margin-left: 1rem; }
	.hero-art { align-self: center; justify-self: end; max-width: 650px; position: relative; width: min(100%, 650px); z-index: 0; } .hero-art::before { background: radial-gradient(circle, rgba(111, 93, 235, .28), transparent 67%); content: ''; inset: 8% -3%; pointer-events: none; position: absolute; } .hero-art svg { display: block; height: auto; position: relative; width: 100%; }
